INSERT INTO public.conta_contabil (empresa_id,conta_reduzida,classificacao,descricao,tipo,natureza,exige_contrato,centro_custo_padrao,entra_fluxo,entra_orcamento,grupo_dre,saldo_inicial,ativo)
SELECT emp.id, src.ord, src.classificacao, src.descricao, src.tipo::conta_tipo, src.natureza::conta_natureza, src.exige_contrato::conta_exige_contrato, src.cc_padrao, src.entra_fluxo, src.entra_orcamento, src.grupo_dre::conta_grupo_dre, 0, true
FROM src CROSS JOIN emp
ON CONFLICT (empresa_id,classificacao) DO NOTHING;

UPDATE public.conta_contabil c SET parent_id=p.id
FROM public.conta_contabil p
WHERE c.empresa_id=p.empresa_id
  AND p.classificacao = regexp_replace(c.classificacao, '\.[^.]+$','')
  AND c.parent_id IS NULL AND c.classificacao <> p.classificacao;

