INSERT INTO public.regra_contabilizacao
  (empresa_id,evento,descricao,prioridade,ativo,exige_contrato,exige_centro_custo,entra_dre,requer_3way_match,requer_pedido,gatilho,observacao,codigo_evento,centro_custo_padrao)
SELECT emp.id, src.evento::regra_evento, src.descricao, src.prioridade, true,
       src.exige_contrato, src.exige_centro_custo, src.entra_dre,
       src.requer_3way_match, src.requer_pedido, src.gatilho, src.observacao,
       src.codigo_evento, src.centro_custo_padrao
FROM src CROSS JOIN emp
WHERE NOT EXISTS (
  SELECT 1 FROM public.regra_contabilizacao r
  WHERE r.empresa_id=emp.id AND r.codigo_evento=src.codigo_evento
);